# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.
# Category: insecure_universal_links

import UIKit

// MARK: - Universal Link Configuration

struct UniversalLinkConfig {
    static let allowedHosts: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    static let allowedSchemes: Set<String> = [
        "https"
    ]
    
    // Define allowed path prefixes and their required authentication levels
    static let allowedRoutes: [String: RouteConfig] = [
        "/profile": RouteConfig(requiresAuth: true, requiresAdmin: false, parameterValidation: .numericID),
        "/payment/confirm": RouteConfig(requiresAuth: true, requiresAdmin: false, parameterValidation: .paymentToken),
        "/admin/settings": RouteConfig(requiresAuth: true, requiresAdmin: true, parameterValidation: .none)
    ]
}

enum ParameterValidation {
    case none
    case numericID
    case paymentToken
}

struct RouteConfig {
    let requiresAuth: Bool
    let requiresAdmin: Bool
    let parameterValidation: ParameterValidation
}

// MARK: - Parsed Universal Link

enum DeepLinkDestination: Equatable {
    case profile(userID: String)
    case paymentConfirm(token: String?, amount: String?)
    case adminSettings
}

struct ParsedUniversalLink {
    let destination: DeepLinkDestination
    let routeConfig: RouteConfig
    let sourceURL: URL
}

// MARK: - Validation Errors

enum UniversalLinkError: Error, CustomStringConvertible {
    case invalidScheme(String?)
    case invalidHost(String?)
    case invalidPath(String)
    case invalidParameter(String)
    case authenticationRequired
    case adminPrivilegeRequired
    case pathTraversalDetected
    case malformedURL
    
    var description: String {
        switch self {
        case .invalidScheme(let scheme):
            return "Invalid scheme: \(scheme ?? "nil"). Only HTTPS is allowed."
        case .invalidHost(let host):
            return "Invalid host: \(host ?? "nil"). Host not in allowlist."
        case .invalidPath(let path):
            return "Invalid path: \(path). Path not in allowed routes."
        case .invalidParameter(let detail):
            return "Invalid parameter: \(detail)"
        case .authenticationRequired:
            return "Authentication required for this route."
        case .adminPrivilegeRequired:
            return "Admin privileges required for this route."
        case .pathTraversalDetected:
            return "Path traversal attempt detected."
        case .malformedURL:
            return "Malformed URL."
        }
    }
}

// MARK: - Universal Link Validator & Parser

final class UniversalLinkHandler {
    
    // Dependency: authentication state provider
    private let authProvider: AuthenticationProviding
    
    init(authProvider: AuthenticationProviding) {
        self.authProvider = authProvider
    }
    
    // MARK: - Public API
    
    func handleUniversalLink(_ url: URL) -> Result<ParsedUniversalLink, UniversalLinkError> {
        // Step 1: Validate URL components
        let validationResult = validateURL(url)
        switch validationResult {
        case .failure(let error):
            logSecurityEvent("Universal link validation failed: \(error)", url: url)
            return .failure(error)
        case .success:
            break
        }
        
        // Step 2: Parse the destination
        let parseResult = parseDestination(from: url)
        switch parseResult {
        case .failure(let error):
            logSecurityEvent("Universal link parsing failed: \(error)", url: url)
            return .failure(error)
        case .success(let parsed):
            // Step 3: Check authorization
            let authResult = checkAuthorization(for: parsed)
            switch authResult {
            case .failure(let error):
                logSecurityEvent("Universal link authorization failed: \(error)", url: url)
                return .failure(error)
            case .success:
                return .success(parsed)
            }
        }
    }
    
    // MARK: - Validation
    
    private func validateURL(_ url: URL) -> Result<Void, UniversalLinkError> {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.malformedURL)
        }
        
        // Validate scheme
        guard let scheme = components.scheme?.lowercased(),
              UniversalLinkConfig.allowedSchemes.contains(scheme) else {
            return .failure(.invalidScheme(components.scheme))
        }
        
        // Validate host
        guard let host = components.host?.lowercased(),
              UniversalLinkConfig.allowedHosts.contains(host) else {
            return .failure(.invalidHost(components.host))
        }
        
        // Check for path traversal attacks
        let path = components.path
        if containsPathTraversal(path) {
            return .failure(.pathTraversalDetected)
        }
        
        // Validate path against allowlist
        let normalizedPath = normalizePath(path)
        let matchedRoute = findMatchingRoute(for: normalizedPath)
        guard matchedRoute != nil else {
            return .failure(.invalidPath(normalizedPath))
        }
        
        return .success(())
    }
    
    private func containsPathTraversal(_ path: String) -> Bool {
        let decodedPath = path.removingPercentEncoding ?? path
        let dangerousPatterns = ["..", "//", "\\", "%2e%2e", "%2f", "%5c"]
        for pattern in dangerousPatterns {
            if decodedPath.lowercased().contains(pattern) {
                return true
            }
        }
        // Also check for null bytes
        if decodedPath.contains("\0") {
            return true
        }
        return false
    }
    
    private func normalizePath(_ path: String) -> String {
        var normalized = path.lowercased()
        // Remove trailing slash
        if normalized.hasSuffix("/") && normalized.count > 1 {
            normalized = String(normalized.dropLast())
        }
        return normalized
    }
    
    private func findMatchingRoute(for normalizedPath: String) -> (String, RouteConfig)? {
        // Try exact match first, then prefix match
        for (routePath, config) in UniversalLinkConfig.allowedRoutes {
            if normalizedPath == routePath {
                return (routePath, config)
            }
            // Allow paths like /profile/123 to match /profile route
            if normalizedPath.hasPrefix(routePath + "/") || normalizedPath == routePath {
                return (routePath, config)
            }
        }
        return nil
    }
    
    // MARK: - Parsing
    
    private func parseDestination(from url: URL) -> Result<ParsedUniversalLink, UniversalLinkError> {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.malformedURL)
        }
        
        let path = normalizePath(components.path)
        let pathComponents = path.split(separator: "/").map(String.init)
        let queryItems = components.queryItems ?? []
        
        guard let (routePath, routeConfig) = findMatchingRoute(for: path) else {
            return .failure(.invalidPath(path))
        }
        
        // Parse based on route
        switch routePath {
        case "/profile":
            return parseProfileLink(pathComponents: pathComponents, routeConfig: routeConfig, url: url)
        case "/payment/confirm":
            return parsePaymentConfirmLink(queryItems: queryItems, routeConfig: routeConfig, url: url)
        case "/admin/settings":
            return parseAdminSettingsLink(routeConfig: routeConfig, url: url)
        default:
            return .failure(.invalidPath(path))
        }
    }
    
    private func parseProfileLink(pathComponents: [String], routeConfig: RouteConfig, url: URL) -> Result<ParsedUniversalLink, UniversalLinkError> {
        // Expected format: /profile/{userID}
        guard pathComponents.count == 2,
              pathComponents[0] == "profile" else {
            return .failure(.invalidParameter("Profile link requires a user ID: /profile/{id}"))
        }
        
        let userIDRaw = pathComponents[1]
        
        // Validate: must be numeric, reasonable length
        let validationResult = validateNumericID(userIDRaw)
        switch validationResult {
        case .failure(let error):
            return .failure(error)
        case .success(let sanitizedID):
            let destination = DeepLinkDestination.profile(userID: sanitizedID)
            return .success(ParsedUniversalLink(destination: destination, routeConfig: routeConfig, sourceURL: url))
        }
    }
    
    private func parsePaymentConfirmLink(queryItems: [URLQueryItem], routeConfig: RouteConfig, url: URL) -> Result<ParsedUniversalLink, UniversalLinkError> {
        // Expected format: /payment/confirm?token=abc123&amount=49.99
        var token: String?
        var amount: String?
        
        for item in queryItems {
            switch item.name.lowercased() {
            case "token":
                if let value = item.value {
                    let tokenResult = validatePaymentToken(value)
                    switch tokenResult {
                    case .failure(let error):
                        return .failure(error)
                    case .success(let validToken):
                        token = validToken
                    }
                }
            case "amount":
                if let value = item.value {
                    let amountResult = validateAmount(value)
                    switch amountResult {
                    case .failure(let error):
                        return .failure(error)
                    case .success(let validAmount):
                        amount = validAmount
                    }
                }
            default:
                // Ignore unknown query parameters
                break
            }
        }
        
        let destination = DeepLinkDestination.paymentConfirm(token: token, amount: amount)
        return .success(ParsedUniversalLink(destination: destination, routeConfig: routeConfig, sourceURL: url))
    }
    
    private func parseAdminSettingsLink(routeConfig: RouteConfig, url: URL) -> Result<ParsedUniversalLink, UniversalLinkError> {
        let destination = DeepLinkDestination.adminSettings
        return .success(ParsedUniversalLink(destination: destination, routeConfig: routeConfig, sourceURL: url))
    }
    
    // MARK: - Parameter Validation
    
    private func validateNumericID(_ raw: String) -> Result<String, UniversalLinkError> {
        // Must be purely numeric, 1-20 digits
        let sanitized = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard !sanitized.isEmpty else {
            return .failure(.invalidParameter("User ID cannot be empty."))
        }
        
        guard sanitized.count <= 20 else {
            return .failure(.invalidParameter("User ID too long."))
        }
        
        let numericRegex = "^[0-9]+$"
        guard sanitized.range(of: numericRegex, options: .regularExpression) != nil else {
            return .failure(.invalidParameter("User ID must be numeric."))
        }
        
        return .success(sanitized)
    }
    
    private func validatePaymentToken(_ raw: String) -> Result<String, UniversalLinkError> {
        // Alphanumeric + hyphens, 1-128 chars
        let sanitized = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard !sanitized.isEmpty else {
            return .failure(.invalidParameter("Payment token cannot be empty."))
        }
        
        guard sanitized.count <= 128 else {
            return .failure(.invalidParameter("Payment token too long."))
        }
        
        let tokenRegex = "^[a-zA-Z0-9\\-_]+$"
        guard sanitized.range(of: tokenRegex, options: .regularExpression) != nil else {
            return .failure(.invalidParameter("Payment token contains invalid characters."))
        }
        
        return .success(sanitized)
    }
    
    private func validateAmount(_ raw: String) -> Result<String, UniversalLinkError> {
        let sanitized = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard !sanitized.isEmpty else {
            return .failure(.invalidParameter("Amount cannot be empty."))
        }
        
        // Must be a valid decimal number
        let amountRegex = "^[0-9]+(\\.[0-9]{1,2})?$"
        guard sanitized.range(of: amountRegex, options: .regularExpression) != nil else {
            return .failure(.invalidParameter("Amount must be a valid decimal (e.g., 49.99)."))
        }
        
        guard let value = Double(sanitized), value > 0, value <= 999999.99 else {
            return .failure(.invalidParameter("Amount out of valid range."))
        }
        
        return .success(sanitized)
    }
    
    // MARK: - Authorization
    
    private func checkAuthorization(for parsed: ParsedUniversalLink) -> Result<Void, UniversalLinkError> {
        if parsed.routeConfig.requiresAuth && !authProvider.isAuthenticated {
            return .failure(.authenticationRequired)
        }
        
        if parsed.routeConfig.requiresAdmin && !authProvider.isAdmin {
            return .failure(.adminPrivilegeRequired)
        }
        
        return .success(())
    }
    
    // MARK: - Logging
    
    private func logSecurityEvent(_ message: String, url: URL) {
        // In production, send to your security logging/monitoring service
        #if DEBUG
        print("[UniversalLink Security] \(message) | URL: \(url.absoluteString)")
        #endif
        // TODO: Send to analytics/security monitoring in production
    }
}

// MARK: - Authentication Provider Protocol

protocol AuthenticationProviding {
    var isAuthenticated: Bool { get }
    var isAdmin: Bool { get }
    var currentUserID: String? { get }
}

// MARK: - Concrete Auth Provider

final class AuthenticationManager: AuthenticationProviding {
    static let shared = AuthenticationManager()
    
    var isAuthenticated: Bool = false
    var isAdmin: Bool = false
    var currentUserID: String?
    
    private init() {}
}

// MARK: - Navigation Router

protocol NavigationRouting {
    func navigate(to destination: DeepLinkDestination, from navigationController: UINavigationController)
    func presentLogin(completion: @escaping (Bool) -> Void)
}

final class DeepLinkRouter: NavigationRouting {
    
    private let linkHandler: UniversalLinkHandler
    private weak var navigationController: UINavigationController?
    
    init(linkHandler: UniversalLinkHandler) {
        self.linkHandler = linkHandler
    }
    
    func setNavigationController(_ navController: UINavigationController) {
        self.navigationController = navController
    }
    
    func handleIncomingURL(_ url: URL) {
        let result = linkHandler.handleUniversalLink(url)
        
        switch result {
        case .success(let parsed):
            guard let navController = navigationController else {
                print("[DeepLinkRouter] No navigation controller available.")
                return
            }
            navigate(to: parsed.destination, from: navController)
            
        case .failure(let error):
            handleError(error)
        }
    }
    
    func navigate(to destination: DeepLinkDestination, from navigationController: UINavigationController) {
        DispatchQueue.main.async {
            switch destination {
            case .profile(let userID):
                let profileVC = ProfileViewController()
                profileVC.userID = userID
                navigationController.pushViewController(profileVC, animated: true)
                
            case .paymentConfirm(let token, let amount):
                let paymentVC = PaymentConfirmViewController()
                paymentVC.paymentToken = token
                paymentVC.amount = amount
                navigationController.pushViewController(paymentVC, animated: true)
                
            case .adminSettings:
                let adminVC = AdminSettingsViewController()
                navigationController.pushViewController(adminVC, animated: true)
            }
        }
    }
    
    func presentLogin(completion: @escaping (Bool) -> Void) {
        DispatchQueue.main.async { [weak self] in
            guard let navController = self?.navigationController else {
                completion(false)
                return
            }
            let loginVC = LoginViewController()
            loginVC.completionHandler = completion
            let loginNav = UINavigationController(rootViewController: loginVC)
            loginNav.modalPresentationStyle = .fullScreen
            navController.present(loginNav, animated: true)
        }
    }
    
    private func handleError(_ error: UniversalLinkError) {
        DispatchQueue.main.async { [weak self] in
            switch error {
            case .authenticationRequired:
                self?.presentLogin { [weak self] success in
                    if success {
                        // Optionally retry the link after login
                        print("[DeepLinkRouter] User authenticated. Retry link if needed.")
                    }
                }
            case .adminPrivilegeRequired:
                self?.showAlert(title: "Access Denied", message: "You do not have permission to access this page.")
            default:
                // For security, don't expose detailed error info to user
                self?.showAlert(title: "Invalid Link", message: "This link is not valid or has expired.")
            }
        }
    }
    
    private func showAlert(title: String, message: String) {
        guard let navController = navigationController else { return }
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        navController.present(alert, animated: true)
    }
}

